  const char *benchtype = "compute with global memory (block strided)";
  double *c = reinterpret_cast<double *>(c_void);
  const long size = static_cast<long>(size_bytes / sizeof(double));
  bool doHalfs = true;

  std::printf("Trade-off type:       %s\n", benchtype);
  std::printf("Elements per thread:  %d\n", ELEMENTS_PER_THREAD);
  std::printf("Thread fusion degree: %d\n", FUSION_DEGREE);
  if (!doHalfs) {
    std::printf("Warning:              Half precision computations are not supported\n");
  }

  double *cd = reinterpret_cast<double *>(std::malloc(size * sizeof(double)));
  if (cd == nullptr) {
    std::fprintf(stderr, "Allocation failed\n");
    std::exit(EXIT_FAILURE);
